import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { HTMLAttributes, ReactNode } from 'react';
/**
 * Вариант заливки бейджа.
 * - primary — насыщенный фон семантического цвета, светлый текст/иконка
 * - secondary — светлый фон, насыщенный текст/иконка
 * - tertiary — прозрачный фон, серый текст, цветная точка (если dot=true)
 */
export type BadgeType = 'primary' | 'secondary' | 'tertiary';
/**
 * Семантический цвет бейджа.
 * danger — ошибка/критичное состояние (красный)
 * warning — предупреждение (оранжевый)
 * success — успех (зелёный)
 * info — информация (синий)
 * neutral — нейтральный (серый)
 * teal — бирюзовый
 * violet — фиолетовый
 * magenta — пурпурный
 * aquamarine — аквамариновый
 */
export type BadgeSemantic = 'danger' | 'warning' | 'success' | 'info' | 'neutral' | 'teal' | 'violet' | 'magenta' | 'aquamarine';
/**
 * Пропсы компонента Badge.
 *
 * Badge — индикативный компонент для отображения статусов, категорий, меток.
 * Не интерактивный, только отображение.
 */
export interface BadgeProps extends Omit<HTMLAttributes<HTMLSpanElement>, 'children'> {
    /**
     * Текст бейджа.
     */
    children: ReactNode;
    /**
     * Вариант заливки: primary (насыщенный фон), secondary (светлый фон), tertiary (без фона, с точкой).
     * @default 'secondary'
     */
    type?: BadgeType;
    /**
     * Семантический цвет: danger, warning, success, info.
     * @default 'info'
     */
    semantic?: BadgeSemantic;
    /**
     * Иконка слева от текста.
     * Используется в primary/secondary. Игнорируется при dot=true.
     */
    icon?: Icons;
    /**
     * Показывать цветную точку слева от текста.
     * Подходит для tertiary. Имеет приоритет над icon.
     * @default false
     */
    dot?: boolean;
    /**
     * Идентификатор для тестов.
     * @default 'Badge'
     */
    dataTestId?: string;
}
